```

But we need to match pattern where LHS compares same operand on both sides? Actually we want same LHS operand and constant RHS. We'll need to identify the variable operand and the constant operand. Could be variable on left, constant on right, or swapped. We'll try to match (fcmp pred X, C) where C is constant. Let's use PatternMatch. We'll need to include "llvm/IR/PatternMatch.h" but it's already included (line 44). So we can use match.

We'll write something like:

```cpp
  // Look for pattern: (fcmp pred X, C1) | (fcmp pred X, C2)
  Value *X;
  const APFloat *C1, *C2;
  if (PredL == PredR &&
      ((match(LHS0, m_Value(X)) && match(LHS1, m_APFloat(C1)) &&
        match(RHS0, m_Specific(X)) && match(RHS1, m_APFloat(C2))) ||
       (match(LHS0, m_Value(X)) && match(LHS1, m_APFloat(C1)) &&
        match(RHS1, m_Specific(X)) && match(RHS0, m_APFloat(C2))) ||
       (match(LHS1, m_Value(X)) && match(LHS0, m_APFloat(C1)) &&
        match(RHS0, m_Specific(X)) && match(RHS1, m_APFloat(C2))) ||
       (match(LHS1, m_Value(X)) && match(LHS0, m_APFloat(C1)) &&
        match(RHS1, m_Specific(X)) && match(RHS0, m_APFloat(C2))))) {
    // Determine which constant is more restrictive based on predicate.
    // For AND we need the more restrictive (subset), for OR we need the less restrictive (superset).
    bool IsLessPred = PredL == FCmpInst::FCMP_OLT || PredL == FCmpInst::FCMP_ULT ||
                      PredL == FCmpInst::FCMP_OLE || PredL == FCmpInst::FCMP_ULE;
    bool IsGreaterPred = PredL == FCmpInst::FCMP_OGT || PredL == FCmpInst::FCMP_UGT ||
                         PredL == FCmpInst::FCMP_OGE || PredL == FCmpInst::FCMP_UGE;
    // If equality predicates? We can also handle OEQ, UEQ, ONE, UNE? Might be more complex.
    if (IsLessPred || IsGreaterPred) {
      int Compare = C1->compare(*C2);
      // If constants are unordered (NaN), they cannot be compared; bail.
      if (Compare == APFloat::cmpUnordered)
        return nullptr;
      // Determine which constant yields superset (larger range) for less predicates:
      // For less: x < C (or x <= C). Larger C makes condition easier to satisfy (superset).
      // For greater: x > C (or x >= C). Smaller C makes condition easier to satisfy.
      bool C1IsSuperset = false;
      if (IsLessPred) {
        // C1 is superset if C1 >= C2 (since larger upper bound).
        C1IsSuperset = Compare == APFloat::cmpGreaterThan || Compare == APFloat::cmpEqual;
      } else { // IsGreaterPred
        // C1 is superset if C1 <= C2 (since lower bound is smaller).
        C1IsSuperset = Compare == APFloat::cmpLessThan || Compare == APFloat::cmpEqual;
      }
      // If AND, we need subset (more restrictive) -> choose the opposite of superset.
      // If OR, we need superset (less restrictive).
      bool ChooseC1 = IsAnd ? !C1IsSuperset : C1IsSuperset;
      return ChooseC1 ? LHS : RHS;
    }
  }
